def linear_search(arr, target):
 """Search for target in arr, return index or -1."""
 for i in range(len(arr)):
 if arr[i] == target:
 return i
 return -1

# Example usage
numbers = [64, 34, 25, 12, 22, 11, 90]
result = linear_search(numbers, 22)
print(f"Found at index: {result}") # Output: Found at index: 4

def linear_search(arr, target):
 """Pythonic linear search using enumerate."""
 for index, value in enumerate(arr):
 if value == target:
 return index
 return -1

public class LinearSearch {
 public static <T> int search(T[] arr, T target) {
 for (int i = 0; i < arr.length; i++) {
 if (arr[i].equals(target)) {
 return i;
 }
 }
 return -1;
 }

 public static void main(String[] args) {
 Integer[] numbers = {64, 34, 25, 12, 22};
 int result = search(numbers, 25);
 System.out.println("Found at: " + result);
 }
}

#include <stdio.h>

int linear_search(int arr[], int n, int target) {
 for (int i = 0; i < n; i++) {
 if (arr[i] == target) {
 return i;
 }
 }
 return -1;
}

int main() {
 int arr[] = {64, 34, 25, 12, 22, 11, 90};
 int n = sizeof(arr) / sizeof(arr[0]);
 int target = 22;

 int result = linear_search(arr, n, target);
 printf("Element found at index: %d\n", result);
 return 0;
}
